o7QQpTDTdjrDM3IP.command:
const effect = item.getEffectByKey("hex");
if (!effect) return;

const EXPANDED = "xA5WgSNCDW5qZuAU";
const BREAK_RESISTANCE = "QuSGYPyc7Eu4Veim";
const IMPROVED = "j96AmO1RKb1DZE2i";

const enhancements = item.enhancements.active;

let value = 1;
let options = {
  ...CONFIG.DC20RPG.DROPDOWN_DATA.physicalDamageTypes,
  ...CONFIG.DC20RPG.DROPDOWN_DATA.elementalDamageTypes,
  ...CONFIG.DC20RPG.DROPDOWN_DATA.mysticalDamageTypes
}
let dmgTypes = [];
if (enhancements.get(EXPANDED)) {
  options = {
    physical: "Physical",
    elemental: "Elemental",
    mystical: "Mystical"
  }
}
if (enhancements.get(IMPROVED)) {
  value += enhancements.get(IMPROVED).number;
}
const selected = await DC20.dialog.SimplePopup.select("Select Damage Type", options);
if (!selected) return;

switch(selected) {
  case "physical":
    dmgTypes = Object.keys(CONFIG.DC20RPG.DROPDOWN_DATA.physicalDamageTypes);
    break;
  case "elemental":
    dmgTypes = Object.keys(CONFIG.DC20RPG.DROPDOWN_DATA.elementalDamageTypes);
    break;
  case "mystical":
    dmgTypes = Object.keys(CONFIG.DC20RPG.DROPDOWN_DATA.mysticalDamageTypes);
    break;
  default:
    dmgTypes = [selected];
}

// Add Vulnerability to the effect
for (const dmgType of dmgTypes) {
  effect.system.changes.push({
    key: `system.damageReduction.damageTypes.${dmgType}.vulnerable`,
    mode: 2,
    value: value
  })
}

// Add Resistance removal to the effect
if (enhancements.get(BREAK_RESISTANCE)) {
  for (const dmgType of dmgTypes) {
    effect.system.changes.push({
      key: `system.damageReduction.damageTypes.${dmgType}.resistance`,
      mode: 5,
      value: false
    })
    effect.system.changes.push({
      key: `system.damageReduction.damageTypes.${dmgType}.resist`,
      mode: 5,
      value: 0
    })
  }
}

